#include<bits/stdc++.h>
using namespace std;
const int N=2005,MOD=1e8;
long long f,n,a[N],dp[N][N];
int main()
{
    cin>>n>>f;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        a[i]%=f;
        dp[i][a[i]]=1;
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=0;j<f;j++)
        {
            dp[i][j]+=(dp[i-1][j]+dp[i-1][(j-a[i]+f)%f])%MOD;
        }
    }
    cout<<dp[n][0];
    return 0;
}
